import React from 'react';
import {View, Text, StyleSheet} from 'react-native';
import type {IDividerComponent} from '@lmb/kitsconcerto-types';
import {useSeparator} from '../../../../Factory';
import {useKitsTheme} from '../../../../Contexts/Theme';

const Divider: React.FC<IDividerComponent> = (props) => {
    const {nativeProps} = useSeparator<any>(props);
    const {
        align = 'center',
        children,
        layout = 'horizontal',
        type: borderType = 'solid',
        unstyled = false,
        ...rest
    } = nativeProps;

    const {resolveToken} = useKitsTheme();
    const dividerColor = resolveToken('divider');

    const isHorizontal = layout === 'horizontal';

    if (unstyled) {
        return (
            <View
                {...rest}
                style={[
                    isHorizontal ? styles.horizontal : styles.vertical,
                    rest.style,
                ]}
            />
        );
    }

    const lineStyle = isHorizontal
        ? [styles.horizontalLine, {borderBottomStyle: borderType, borderBottomColor: dividerColor}]
        : [styles.verticalLine, {borderLeftStyle: borderType, borderLeftColor: dividerColor}];

    if (!children) {
        return (
            <View
                {...rest}
                style={[
                    isHorizontal ? styles.horizontal : styles.vertical,
                    isHorizontal
                        ? {borderBottomWidth: StyleSheet.hairlineWidth, borderBottomColor: dividerColor, borderStyle: borderType}
                        : {borderLeftWidth: StyleSheet.hairlineWidth, borderLeftColor: dividerColor, borderStyle: borderType},
                    rest.style,
                ]}
            />
        );
    }

    const alignMap: Record<string, 'flex-start' | 'center' | 'flex-end'> = {
        left: 'flex-start',
        top: 'flex-start',
        center: 'center',
        right: 'flex-end',
        bottom: 'flex-end',
    };
    const justifyContent = alignMap[align] ?? 'center';

    return (
        <View
            {...rest}
            style={[
                isHorizontal ? styles.horizontalWithContent : styles.verticalWithContent,
                {justifyContent},
                rest.style,
            ]}>
            <View style={[
                isHorizontal ? styles.lineSegment : styles.lineSegmentVertical,
                {backgroundColor: dividerColor},
                align === 'left' || align === 'top' ? {flex: 0, width: isHorizontal ? 24 : undefined, height: !isHorizontal ? 24 : undefined} : {flex: 1},
            ]} />
            <Text style={[styles.contentText, {color: resolveToken('text-secondary')}]}>
                {children}
            </Text>
            <View style={[
                isHorizontal ? styles.lineSegment : styles.lineSegmentVertical,
                {backgroundColor: dividerColor},
                align === 'right' || align === 'bottom' ? {flex: 0, width: isHorizontal ? 24 : undefined, height: !isHorizontal ? 24 : undefined} : {flex: 1},
            ]} />
        </View>
    );
};

const styles = StyleSheet.create({
    horizontal: {
        width: '100%',
        flexDirection: 'row',
    },
    vertical: {
        height: '100%',
        flexDirection: 'column',
    },
    horizontalWithContent: {
        width: '100%',
        flexDirection: 'row',
        alignItems: 'center',
        gap: 12,
    },
    verticalWithContent: {
        height: '100%',
        flexDirection: 'column',
        alignItems: 'center',
        gap: 12,
    },
    horizontalLine: {
        width: '100%',
    },
    verticalLine: {
        height: '100%',
    },
    lineSegment: {
        height: StyleSheet.hairlineWidth,
        flex: 1,
    },
    lineSegmentVertical: {
        width: StyleSheet.hairlineWidth,
        flex: 1,
    },
    contentText: {
        fontSize: 14,
    },
});

export default Divider;
